def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            exp_penalty = 0
            for a in range(1, 5):
                term = ((ratio - 2) ** a) / (a * 1.5)
                if a % 2 == 0:
                    exp_penalty -= term
                else:
                    exp_penalty += term
            base_score = (ratio ** 4) + exp_penalty
            noise = 0
            for n in range(1, 4):
                noise += np.sin(ratio * n * np.pi) / (n * 3)
            priorities[i] = max(0, base_score + noise)
        elif 1 < ratio <= 2:
            accum = 0
            for b in range(1, 7):
                factor = (-1) ** (b+1)
                accum += factor * (ratio ** b) / (b * 2)
            adj = 0
            for c in range(1, 5):
                adj += np.log1p(ratio * c) / (c + 2)
            priorities[i] = abs(accum) * adj
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                score += sign * (ratio ** j) / (j ** 1.2)
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7
            priorities[i] = abs(score) * multiplier
            if ratio > 0.75:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m + 0.5)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if np.isfinite(priorities[i]) and priorities[i] > 50:
            sub_penalty = 0
            for x in range(1, 4):
                sub_penalty += np.exp(-ratio * x) / (x * 2)
            priorities[i] -= sub_penalty
            if priorities[i] < 0:
                priorities[i] = 0
    return priorities
